from boto3 import client as s3client
import requests
from selenium import webdriver
from PIL import Image
import io
    
def takeScreenshot(url):   
       # Setup Selenium WebDriver with PhantomJS or Chrome  
       driver = webdriver.PhantomJS()  if 'phantomjs' in sys.modules else \
                 webdriver.Chrome('<path_to>/chromedriver')    
       
       try:    # Try to open the URL and take screenshot using selenium  
           driver.get(url)     
           
           image = Image.open(io.BytesIO(requests.get(driver.execute_script('return document.querySelector("body").innerHTML')).content)) 
       finally:    # Always clean up the browser session and quit it when done  
               driver.quit()    
       
       return image     
        
def storeScreenshotInAWS(image, bucket_name):         
           s3 = boto3.client('s3', aws_access_key_id='YOUR_AWS_ACCESS_KEY', 
                             aws_secret_access_key='YOUR_SECRET_ACCESS_KEY')   # Initialize S3 client   
           
           in_mem_file = io.BytesIO()    
        
           image.save(in_mem_file, format=image.format) 
         
           s3.put_object(Body=in_mem_file.getvalue(), Bucket=bucket_name , Key='screenshot-{}.png'.format(url))   # Store the image in S3 bucket